+fn diagonal_nan_cutoff(a: &[f64], n: usize) -> Option<usize> {
+    let mut max_diag_nan = None;
+    for row in 0..n {
+        for col in 0..n {
+            let value = a[row * n + col];
+            if value.is_nan() {
+                if row != col {
+                    return None;
+                }
+                max_diag_nan = Some(row);
+            }
+        }
+    }
+    max_diag_nan
+}
